/**
 * @brief rtc time set
 *
 * @param[in] time_sec: rtc time seconds
 *
* @return OPRT_OK on success. Others on error, please refer to tuya_error_code.h
 */
OPERATE_RET tkl_rtc_time_set(TIME_T time_sec)
{
    rtc_parameter_struct rtc_para;
    rtc_current_time_get(&rtc_para);

    rtc_para.hour = time_sec / 3600;
    rtc_para.minute = (time_sec % 3600) / 60;
    rtc_para.second = (time_sec % 3600) % 60;

    if (rtc_para.hour > 12) {
        rtc_para.am_pm = RTC_PM;
    }
    else {
        rtc_para.am_pm = RTC_AM;
    }

    if (ERROR == rtc_init(&rtc_para)) {
        return OPRT_COM_ERROR;
    }

    return OPRT_OK;
}

/**
 * @brief rtc time get
 *
 * @param[in] time_sec:rtc time seconds
 *
* @return OPRT_OK on success. Others on error, please refer to tuya_error_code.h
 */
OPERATE_RET tkl_rtc_time_get(TIME_T *time_sec)
{
    rtc_parameter_struct rtc_para;
    rtc_current_time_get(&rtc_para);

    *time_sec = rtc_para.hour * 3600 + rtc_para.minute * 60 + rtc_para.second;

    return OPRT_OK;
}
